213	            <Chip
214	              key={p.value}
215	              label={p.label}
216	              active={row.platform === p.value}
217	              onPress={() => onPlatformPick(p.value)}
218	              accessibilityLabel={`Platform ${p.label}`}
219	              testID={`wizard-step2-row-${index}-platform-${p.value}`}
