231	              label={m.label}
232	              active={row.metric === m.value}
233	              onPress={() => onMetricPick(m.value)}
234	              accessibilityLabel={`Metric ${m.label}`}
235	              testID={`wizard-step2-row-${index}-metric-${m.value}`}
236	            />
237	          ))}
238	        </View>
239	      </View>
240	
241	      <View style={styles.thresholdRow}>
242	        <View style={[styles.opBadge, shadows.hard]}>
243	          <Text style={[textStyles.micro, styles.opBadgeText]} allowFontScaling={false}>
244	            {'\u2265'}
245	          </Text>
246	        </View>
247	        <View style={[styles.inputWrap, shadows.hard]}>
248	          <TextInput
