250	            onChangeText={onThresholdChange}
251	            placeholder="0"
252	            placeholderTextColor={colors.ink40}
253	            keyboardType="number-pad"
254	            maxLength={12}
255	            style={[textStyles.body, styles.input]}
256	            accessibilityLabel="Threshold"
257	            testID={`wizard-step2-row-${index}-threshold`}
