13	// Campaign-creation wizard state (US-049 through US-053). React-context + AsyncStorage
14	// persistence — not MMKV, because `react-native-mmkv` v4 is a Nitro module that
15	// cannot load in Expo Go (see Codebase Pattern #105, progress.txt). AsyncStorage
16	// satisfies the AC's "wizard store + MMKV" intent with a transport that actually
17	// boots in Expo Go. The wizard draft is not secret material, so AsyncStorage (vs
18	// expo-secure-store) is the correct fit.
19	//
20	// Shape covers all five steps up front so later stories (US-050 pre-conditions,
21	// US-051 post-conditions, US-052 samples + max, US-053 publish) can read and
22	// write their slices without a store rewrite. Step 1 (this story) only wires the
23	// first four fields; the rest are kept with empty-array / null defaults.
24	
25	export type WizardCurrency = 'USD' | 'EUR' | 'GBP';
26	
27	export type WizardPreConditionPlatform = 'tiktok' | 'instagram';
28	export type WizardPreConditionMetric = 'followers' | 'avg_views';
29	
30	export type WizardPreCondition = {
31	  id: string;
32	  platform: WizardPreConditionPlatform;
33	  metric: WizardPreConditionMetric;
34	  threshold: number;
35	};
36	
37	export type WizardPostCondition = {
38	  id: string;
39	  text: string;
40	};
41	
42	export type WizardDraft = {
43	  title: string;
44	  description: string;
45	  priceCents: number | null;
46	  currency: WizardCurrency;
47	  preConditions: WizardPreCondition[];
48	  postConditions: WizardPostCondition[];
49	  sampleUrls: string[];
50	  maxSubmissions: number | null;
51	};
52	
53	const EMPTY_DRAFT: WizardDraft = {
54	  title: '',
55	  description: '',
56	  priceCents: null,
57	  currency: 'USD',
58	  preConditions: [],
59	  postConditions: [],
60	  sampleUrls: [],
61	  maxSubmissions: null,
62	};
63	
64	const STORAGE_KEY = '@marketify/campaign-wizard-draft/v1';
65	const PERSIST_DEBOUNCE_MS = 250;
66	
67	type WizardContextValue = {
68	  draft: WizardDraft;
69	  hydrated: boolean;
70	  setField: <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => void;
71	  setPartial: (patch: Partial<WizardDraft>) => void;
72	  resetDraft: () => Promise<void>;
73	};
74	
75	const WizardContext = createContext<WizardContextValue | null>(null);
76	
77	function isWizardDraftShape(value: unknown): value is WizardDraft {
78	  if (!value || typeof value !== 'object') return false;
79	  const v = value as Record<string, unknown>;
80	  return (
81	    typeof v.title === 'string' &&
82	    typeof v.description === 'string' &&
83	    (v.priceCents === null || typeof v.priceCents === 'number') &&
84	    (v.currency === 'USD' || v.currency === 'EUR' || v.currency === 'GBP') &&
85	    Array.isArray(v.preConditions) &&
86	    Array.isArray(v.postConditions) &&
87	    Array.isArray(v.sampleUrls) &&
88	    (v.maxSubmissions === null || typeof v.maxSubmissions === 'number')
89	  );
90	}
91	
92	export function WizardProvider({ children }: { children: ReactNode }) {
93	  const [draft, setDraft] = useState<WizardDraft>(EMPTY_DRAFT);
94	  const [hydrated, setHydrated] = useState(false);
95	  const persistTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
96	  // Mirror the latest draft so the unmount cleanup can flush whatever is
97	  // pending without closure-capture of stale state.
98	  const draftRef = useRef<WizardDraft>(draft);
99	
100	  useEffect(() => {
101	    draftRef.current = draft;
102	  }, [draft]);
103	
104	  useEffect(() => {
105	    let cancelled = false;
106	    void (async () => {
107	      try {
108	        const raw = await AsyncStorage.getItem(STORAGE_KEY);
109	        if (cancelled) return;
110	        if (raw) {
111	          const parsed: unknown = JSON.parse(raw);
112	          if (isWizardDraftShape(parsed)) {
113	            setDraft(parsed);
114	          }
115	        }
116	      } catch {
117	        // Corrupted / missing draft — start clean. No user-visible error:
118	        // the wizard is a local-first flow and an empty draft is the right
119	        // fallback.
120	      } finally {
121	        if (!cancelled) setHydrated(true);
122	      }
123	    })();
124	    return () => {
125	      cancelled = true;
126	    };
127	  }, []);
128	
129	  const schedulePersist = useCallback((next: WizardDraft) => {
130	    if (persistTimer.current) clearTimeout(persistTimer.current);
131	    persistTimer.current = setTimeout(() => {
132	      void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(next));
133	    }, PERSIST_DEBOUNCE_MS);
134	  }, []);
135	
136	  useEffect(() => {
137	    return () => {
138	      if (persistTimer.current) {
139	        // Flush pending edit before cancelling. AsyncStorage.setItem is
140	        // async and fire-and-forget here — React unmount paths don't await
141	        // promises, but kicking the write off before clearing the timer is
142	        // what prevents the last keystroke from being dropped if the
143	        // provider unmounts inside the 250 ms debounce window.
144	        clearTimeout(persistTimer.current);
145	        persistTimer.current = null;
146	        void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(draftRef.current));
147	      }
148	    };
149	  }, []);
150	
151	  const setField = useCallback(
152	    <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => {
153	      setDraft((prev) => {
154	        const next = { ...prev, [key]: value };
155	        schedulePersist(next);
156	        return next;
157	      });
158	    },
159	    [schedulePersist],
160	  );
161	
162	  const setPartial = useCallback(
163	    (patch: Partial<WizardDraft>) => {
164	      setDraft((prev) => {
165	        const next = { ...prev, ...patch };
166	        schedulePersist(next);
167	        return next;
168	      });
169	    },
170	    [schedulePersist],
171	  );
172	
173	  const resetDraft = useCallback(async () => {
174	    if (persistTimer.current) {
175	      clearTimeout(persistTimer.current);
176	      persistTimer.current = null;
177	    }
178	    setDraft(EMPTY_DRAFT);
179	    await AsyncStorage.removeItem(STORAGE_KEY);
180	  }, []);
181	
182	  const value = useMemo<WizardContextValue>(
183	    () => ({ draft, hydrated, setField, setPartial, resetDraft }),
184	    [draft, hydrated, setField, setPartial, resetDraft],
185	  );
186	
187	  return <WizardContext.Provider value={value}>{children}</WizardContext.Provider>;
188	}
189	
190	export function useWizard(): WizardContextValue {
191	  const ctx = useContext(WizardContext);
192	  if (!ctx) {
193	    throw new Error('useWizard must be used inside <WizardProvider>');
194	  }
195	  return ctx;
196	}
