32	// Filter chip per docs/design.md §5.1 (horizontal chip row) + §1.2 (primarySoft bg
33	// when selected). Press = spring.soft scale-to-0.97 per §1.4 line 100; haptic uses
34	// `selectionAsync` since toggling is a discrete selection change, not an impact.
35	export function Chip({
36	  label,
37	  active = false,
38	  onPress,
39	  disabled = false,
40	  style,
41	  accessibilityLabel,
42	  testID,
43	}: ChipProps) {
44	  const reduced = useReducedMotion();
45	  const pressed = useSharedValue(0);
46	  const interactive = !disabled && !!onPress;
47	
48	  // Shadow collapses on press by fading shadowOpacity to 0 while the chip
49	  // translates (3,3) — same compound-prop workaround the Button primitive uses
50	  // since iOS `shadowOffset` is not animatable through `useAnimatedStyle`.
51	  const animatedStyle = useAnimatedStyle(() => {
52	    const v = pressed.value;
53	    return {
54	      transform: [
55	        { translateX: v * 3 },
56	        { translateY: v * 3 },
57	        { scale: 1 - v * 0.03 },
58	      ],
59	      shadowOpacity: 1 - v,
60	    };
61	  });
62	
63	  const handlePressIn = useCallback(() => {
64	    if (!interactive) return;
65	    void Haptics.selectionAsync();
66	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
67	  }, [interactive, pressed, reduced]);
68	
69	  const handlePressOut = useCallback(() => {
70	    if (!interactive) return;
71	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
72	  }, [interactive, pressed, reduced]);
73	
74	  const bg = disabled ? colors.hairline : active ? colors.primarySoft : colors.surface;
75	  const borderColor = disabled ? colors.ink40 : colors.ink;
76	  const textColor = disabled ? colors.ink40 : active ? colors.primaryDeep : colors.ink;
77	
78	  return (
79	    <Pressable
80	      onPress={interactive ? onPress : undefined}
81	      onPressIn={handlePressIn}
82	      onPressOut={handlePressOut}
83	      disabled={!interactive}
84	      accessibilityRole="checkbox"
85	      accessibilityLabel={accessibilityLabel ?? label}
86	      accessibilityState={{ checked: active, disabled: !interactive }}
87	      testID={testID}
88	    >
89	      <Animated.View
90	        style={[
91	          styles.base,
92	          { backgroundColor: bg, borderColor },
93	          disabled ? shadows.none : shadows.hard,
94	          animatedStyle,
95	          style,
96	        ]}
97	      >
98	        <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
99	          {label}
100	        </Text>
101	      </Animated.View>
102	    </Pressable>
103	  );
104	}
