69	function BaseButton({
70	  label,
71	  onPress,
72	  disabled = false,
73	  loading = false,
74	  variant,
75	  style,
76	  accessibilityLabel,
77	  testID,
78	}: ButtonProps & { variant: Variant }) {
79	  const interactive = !disabled && !loading;
80	  const { animatedStyle, handlePressIn, handlePressOut } = useBaseButton(interactive);
81	
82	  const variantStyle = variant === 'primary' ? styles.primary : styles.secondary;
83	  const labelColor = disabled ? colors.ink40 : colors.ink;
